  i.json._log = {
    runId: startedAt,
    workflow: i.json._log?.workflow || null,
    executionId: i.json._log?.executionId || null,
    startedAt,
    ok: 0,
    ko: 0,
    actions: [],
    failedNodes: {}
  };
  return i;
});

return items.map(i => {
  const log = i.json._log || {};

  // LIGNE 5 CORRIGÉE
  const nodeName = i.json._lastNode || 'UnknownNode';

  const failed = !!i.json._hadError || !!i.json.error;

  // Message adaptatif
  const msg = i.json.error?.message || 
              i.json._errMsg || 
              (failed ? 'Erreur détectée' : 'Succès');

  (log.actions ||= []).push({ node: nodeName, ok: !failed, msg });

  if (failed) {
    log.ko = (log.ko || 0) + 1;
    log.failedNodes = log.failedNodes || {};
    log.failedNodes[nodeName] = true;
  } else {
    log.ok = (log.ok || 0) + 1;
  }

  i.json._log = log;
  return i;
});

