const items = $input.all();
const processedItems = [];

for (const item of items) {
  // Récupération de la propriété "property_r_f_rence_n8n"
  const textData = item.json.property_r_f_rence_n8n || '';

  // Initialisation des variables
  let parsedData = {
    nom_tache: '',
    id_database: '',
    id_page: '',
    id_fournisseur: '', // Seulement pour les certificats
    ticket: null        // NOUVEAU : numéro de ticket
  };

  if (textData) {
    // DEBUG : Vérifier le format exact du texte
    console.log("Texte brut:", textData);
    console.log("Contient \\n littéral:", textData.includes('\\n'));
    console.log("Contient saut de ligne:", textData.includes('\n'));

    // Normalisation : Remplacer les \n littéraux par de vrais sauts de ligne
    const normalizedText = textData.replace(/\\n/g, '\n');
    console.log("Texte normalisé:", normalizedText);

    // Découpage du texte par lignes (après normalisation)
    const lignes = normalizedText.split('\n');

    // [1] Nom de la tâche (première ligne)
    if (lignes[0]) {
      parsedData.nom_tache = lignes[0].trim();
    }

    // Parsing des lignes suivantes
    for (let i = 1; i < lignes.length; i++) {
      const ligne = lignes[i].trim();

      // [2] ID Database
      if (ligne.startsWith('ID Database:')) {
        parsedData.id_database = ligne.replace('ID Database:', '').trim();
      }

      // [3] ID Page
      if (ligne.startsWith('ID Page:')) {
        parsedData.id_page = ligne.replace('ID Page:', '').trim();
      }

      // [4] ID Fournisseur (uniquement pour les certificats)
      if (ligne.startsWith('ID Fournisseur :')) {
        parsedData.id_fournisseur = ligne.replace('ID Fournisseur :', '').trim();
      }

      // [5] NOUVEAU : Ticket (extraction du numéro)
      if (ligne.startsWith('Ticket :') || ligne.startsWith('Ticket:')) {
        const ticketText = ligne.replace(/Ticket\s*:\s*/i, '').trim();
        const ticketNumber = parseInt(ticketText, 10);

        // Vérification que c'est bien un nombre valide
        if (!isNaN(ticketNumber)) {
          parsedData.ticket = ticketNumber;
          console.log(`Ticket extrait: ${ticketNumber}`);
        } else {
          console.log(`Erreur parsing ticket: "${ticketText}" n'est pas un nombre valide`);
        }
      }
    }
  }

  // LOGIQUE CORRIGÉE : Gestion de la date de planification  
  let datePlanification = item.json["Date de planification"];

  // Vérifier si la date de planification est null (dans l'objet .date)
  if (!datePlanification || datePlanification.date === null || datePlanification.date === undefined) {
    const dateCreation = item.json["Date de créeation"];

    if (dateCreation && dateCreation.created_time) {
      // Convertir created_time ISO vers format date objet Notion
      const dateOnly = dateCreation.created_time.split('T')[0]; // "2025-09-03T23:41:00.000Z" → "2025-09-03"

      // Reconstruire l'objet complet avec la nouvelle date
      datePlanification = {
        ...datePlanification, // Garde id, type, etc.
        "date": {
          "start": dateOnly,
          "end": null,
          "time_zone": null
        }
      };

      console.log(`Date planification mise à jour depuis created_time: ${dateOnly}`);
    }
  }

  // Détermination du type de base d'archive basé sur le nom de tâche
  let type_archive = '';
  switch(parsedData.nom_tache.toLowerCase()) {
    case 'calibration':
      type_archive = 'Archive_Calibration';
      break;
    case 'maintenance':
      type_archive = 'Archive_Maintenance';
      break;
    case 'deviation':
      type_archive = 'Archive_Deviation';
      break;
    case 'certificat':
      type_archive = 'Archive_Certificat';
      break;
    case 'qualité':
    case 'qualite':
      type_archive = 'Archive_Qualite';
      break;
    case 'tâche':
    case 'tache':
      type_archive = 'Archive_Taches_Recurrentes';
      break;
    default:
      type_archive = 'Archive_Autres';
  }

  // Ajout des données parsées à l'item
  processedItems.push({
    json: {
      ...item.json,
      // MISE À JOUR de la date de planification
      property_date_de_planification: datePlanification,
      // Données parsées structurées
      parsed_data: parsedData,
      // Variables directement exploitables pour la suite du workflow
      nom_tache: parsedData.nom_tache,
      id_database_origine: parsedData.id_database,
      id_page_origine: parsedData.id_page,
      id_fournisseur: parsedData.id_fournisseur,
      ticket_number: parsedData.ticket,  // NOUVEAU : ticket comme number
      type_archive: type_archive,
      // Boolean pour identifier les certificats
      is_certificat: parsedData.nom_tache.toLowerCase() === 'certificat'
    }
  });
}

return processedItems;

